import{_ as a,o as t,c as l,ag as r}from"./chunks/framework.eQLvDOR_.js";const f=JSON.parse('{"title":"self-healing-feedback-loop","description":"","frontmatter":{"title":"self-healing-feedback-loop","concept":"自愈反馈闭环","concept_id":"self-healing-feedback-loop","aliases":[],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Why Your “AI-First” Strategy Is Probably Wrong.md"],"related_concepts":["[[ai-native-ci-cd]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/self-healing-feedback-loop.md","filePath":"wiki/concepts/self-healing-feedback-loop.md","lastUpdated":null}'),o={name:"wiki/concepts/self-healing-feedback-loop.md"};function i(c,e,n,s,d,h){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="自愈反馈闭环-self-healing-feedback-loop" tabindex="-1">自愈反馈闭环 (Self-Healing Feedback Loop) <a class="header-anchor" href="#自愈反馈闭环-self-healing-feedback-loop" aria-label="Permalink to &quot;自愈反馈闭环 (Self-Healing Feedback Loop)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>一个无人干预或者极少人工干预的全自动化环路，它将线上的监控告警直接转化为工单，然后驱动 AI 开发补丁并自动化验证部署直至工单闭环。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>跨平台融合</strong>：将 CloudWatch 或 Sentry 等警报进行聚合，然后打分转化为包含上下文的确定性修补任务（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Why Your “AI-First” Strategy Is Probably Wrong.html">[Agent_Architecture] Why Your “AI-First” Strategy Is Probably Wrong.md</a>）</li><li><strong>非人工触发链</strong>：在这个环路中，无论是发现工单，排查根因还部署后再次核验结单的过程，完全由系统主动巡回检测来承载。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>在建立一个复杂的 Agent 团队后，最关键的一步是为它们外接业务层面的 Metric，只有确保它们能够在制造 Bug 后自己发现并进入排期和回归通道，高频交付才有价值。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/ai-native-ci-cd.html">ai-native-ci-cd</a> — 这个系统往往强依赖稳定和快速回滚的 CICD 通道。</li></ul>',9)])])}const b=a(o,[["render",i]]);export{f as __pageData,b as default};
